137→                repostSource: journal?.repost_source || null
138→            };
139→        }
140→
141→        if(!statePostData){
142→            return null;
143→        }
144→
145→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
146→        const parsedContent = ParseContent(statePostData?.content);
