148→
149→        return {
150→            postType: inferredPostType,
151→            content: statePostData?.content,
152→            canvasDoc: canvasDoc,
153→            wholeText: inferredPostType === 'canvas'
154→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
155→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
156→            title: statePostData?.title,
157→            userId: statePostData?.userId,
158→            name: statePostData?.name,
159→            avatar: statePostData?.avatar,
160→            created_at: statePostData?.created_at,
161→            journalId: statePostData?.journalId,
162→            isLiked: statePostData?.isLiked,
163→            commentsCount: statePostData?.commentsCount || 0,
