        className="cv-action-btn cv-action-btn--end"
        onClick={(e) => {
            e.stopPropagation();
            if(!session) return openAuthModal?.();
            setShowRepostModal(true);
        }}
    >
        {/* SVG icon */}
        <span>Repost</span>
    </button>
)}
```
- **Line 670-695:** Modal rendering with post data transformation
```javascript
{showRepostModal && postData && (
    <RepostModal
        journal={{
            id: postData.journalId,
